--changeset roman:rotorcraft-airframe-specs labels:flights,rotorcraft,airframe-specs
-- Per-variant rotorcraft POH/reference limits for exceedance calculation.
CREATE TABLE rotorcraft_airframe_specs (
    id INT NOT NULL AUTO_INCREMENT,

    airframe_id INT NULL,

    manufacturer VARCHAR(64) NOT NULL,
    model VARCHAR(64) NOT NULL,
    series VARCHAR(64) NOT NULL DEFAULT '',
    year INT NULL,
    usage_type VARCHAR(64) NULL,
    helicopter_type VARCHAR(64) NULL,
    seats INT NULL,
    landing_gear VARCHAR(32) NULL,

    max_gross_weight_lbs DOUBLE NULL,
    min_flying_weight_lbs DOUBLE NULL,
    empty_weight_lbs DOUBLE NULL,

    mr_type VARCHAR(64) NULL,
    mr_number_blades INT NULL,
    mr_diameter_in DOUBLE NULL,
    mr_inboard_blade_chord_in DOUBLE NULL,
    mr_outboard_blade_chord_in DOUBLE NULL,
    mr_blade_twist_deg DOUBLE NULL,
    mr_tip_speed_102pct_rpm_fps DOUBLE NULL,
    mr_airfoil VARCHAR(64) NULL,
    mr_power_on_max_continuous_pct VARCHAR(32) NULL,
    mr_power_on_max_continuous_rpm DOUBLE NULL,
    mr_power_on_min_continuous_pct VARCHAR(32) NULL,
    mr_power_on_min_continuous_rpm DOUBLE NULL,
    mr_power_off_max_continuous_pct VARCHAR(32) NULL,
    mr_power_off_max_continuous_rpm DOUBLE NULL,
    mr_power_off_min_continuous_pct VARCHAR(32) NULL,
    mr_hub_material VARCHAR(64) NULL,
    mr_blade_material VARCHAR(64) NULL,
    mr_blade_area_ft2 DOUBLE NULL,
    mr_disk_area_ft2 DOUBLE NULL,

    tr_type VARCHAR(64) NULL,
    tr_number_blades INT NULL,
    tr_diameter_in DOUBLE NULL,
    tr_power_on_max_continuous_rpm DOUBLE NULL,
    tr_blade_chord_in DOUBLE NULL,
    tr_blade_twist_deg DOUBLE NULL,
    tr_tip_speed_102pct_rpm_fps DOUBLE NULL,
    distance_mr_to_tr_in DOUBLE NULL,
    tr_blade_material VARCHAR(64) NULL,
    tr_blade_area_ft2 DOUBLE NULL,
    tr_disk_area_ft2 DOUBLE NULL,

    span_in DOUBLE NULL,
    area_ft2 DOUBLE NULL,

    vne_kias VARCHAR(32) NULL,
    vma_kias VARCHAR(32) NULL,
    vg_kias VARCHAR(32) NULL,
    vy_kias VARCHAR(32) NULL,
    vto_kias VARCHAR(32) NULL,
    vc_kias VARCHAR(32) NULL,
    vapp_kias VARCHAR(32) NULL,
    vauto_kias VARCHAR(32) NULL,
    vturb_kias VARCHAR(32) NULL,
    vlo_kias VARCHAR(32) NULL,
    vle_kias VARCHAR(32) NULL,
    vtd_kias VARCHAR(32) NULL,

    engine_made VARCHAR(64) NULL,
    engine_model VARCHAR(64) NULL,
    engine_number INT NULL,
    takeoff_power DOUBLE NULL,
    manufacturers_rating_shp DOUBLE NULL,
    max_continuous_rating_shp DOUBLE NULL,
    max_fuel_pressure_psi DOUBLE NULL,
    turbine_outlet_temp_aeo_max_continuous_c DOUBLE NULL,
    max_operational_pressure_altitude_ft DOUBLE NULL,
    max_pressure_altitude_takeoff_landing_ft DOUBLE NULL,
    min_sl_operation_air_temp_c DOUBLE NULL,
    max_sl_operation_air_temp_c DOUBLE NULL,
    takeoff_epndb DOUBLE NULL,
    flyover_epndb DOUBLE NULL,
    approach_epndb DOUBLE NULL,
    lb_per_shp DOUBLE NULL,
    lb_per_ft2 DOUBLE NULL,

    PRIMARY KEY (id),
    CONSTRAINT uq_rotorcraft_airframe_specs_identity UNIQUE (manufacturer, model, series),
    CONSTRAINT fk_rotorcraft_airframe_specs_airframe
        FOREIGN KEY (airframe_id) REFERENCES airframes (id)
);

